import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as t,f as c}from"./app-7cfa41e7.js";const i={},o=c('<h3 id="梦" tabindex="-1"><a class="header-anchor" href="#梦" aria-hidden="true">#</a> 梦？</h3><p>梦里会发生各种离奇的事情，这也让我每天从这种离奇的事情里面惊醒，但一天过后发现梦里的事情忘得一干二净，梦里会梦到许多人，但我发现每个梦只有我和另外一个人，这样的梦已经做了无数次了吧，但始终都记不住这到底是什么。</p><h3 id="关于" tabindex="-1"><a class="header-anchor" href="#关于" aria-hidden="true">#</a> 关于</h3><p>常常喜欢谈天说地，聊聊各种想聊的，这种状态是悠闲的，我时不时还回想起五一旅游时的美景，感觉那就是关于美好的一场梦，梦有许多，谁知道下一次这样的梦又是什么时候呢？</p><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/blog/20230429_084150.jpg" alt="20230429_084150" tabindex="0" loading="lazy"><figcaption>20230429_084150</figcaption></figure><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/blog/20230429_091811.jpg" alt="20230429_091811" tabindex="0" loading="lazy"><figcaption>20230429_091811</figcaption></figure>',6),r=[o];function n(s,d){return a(),t("div",null,r)}const l=e(i,[["render",n],["__file","514.html.vue"]]);export{l as default};
